ReportUtil = {}

local function getPlayerGameTime(player)
    local minute = (os.time() - player.loginTime) / 60
    if minute <= 2 then
        return "0_2_minutes"
    elseif minute > 2 and minute <= 4 then
        return "2_4_minutes"
    elseif minute > 4 and minute <= 6 then
        return "4_6_minutes"
    elseif minute > 6 and minute <= 10 then
        return "6_10_minutes"
    elseif minute > 10 and minute <= 15 then
        return "10_15_minutes"
    elseif minute > 15 and minute <= 20 then
        return "15_20_minutes"
    elseif minute > 20 and minute <= 30 then
        return "20_30_minutes"
    else
        return "30_INF_minutes"
    end
end

